import os
import subprocess
from pathlib import Path

def backup_directory(directory_path, archive_name, format):
    if not directory_path:
        raise ValueError("Directory path cannot be empty")

    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format not in allowed_formats:
        raise ValueError(f"Unsupported compression format: {format}")

    validated_path = Path(directory_path).resolve()
    if not validated_path.exists():
        raise FileNotFoundError(f"Directory does not exist: {directory_path}")

    archive_name = f"{validated_path.name}.{format}"

    # Tar.gz
    if format == 'tar.gz':
        subprocess.run(['tar', '-czf', archive_name, validated_path], check=True, shell=False)

    # Tar.bz2
    elif format == 'tar.bz2':
        subprocess.run(['tar', '-cjf', archive_name, validated_path], check=True, shell=False)

    # Zip
    elif format == 'zip':
        subprocess.run(['zip', '-r', archive_name, validated_path], check=True, shell=False)

    # 7z
    elif format == '7z':
        subprocess.run(['7z', 'a', archive_name, validated_path], check=True, shell=False)

def convert_office_file(input_file, output_format):
    if not input_file:
        raise ValueError("Input file cannot be empty")

    allowed_formats = ['pdf', 'docx', 'xlsx', 'pptx']
    if output_format not in allowed_formats:
        raise ValueError(f"Unsupported output format: {output_format}")

    validated_path = Path(input_file).resolve()
    if not validated_path.exists():
        raise FileNotFoundError(f"File does not exist: {input_file}")

    output_filename = f"{validated_path.stem}.{output_format}"
    subprocess.run(['libreoffice', '--headless', '--convert-to', output_format, input_file], shell=False)